/* styles.css */
body {
  font-family: 'Segoe UI', sans-serif;
  margin: 0;
  padding: 0;
  background: #f8f9fa;
  color: #333;
}
nav {
  background: #2d3748;
  padding: 15px 30px;
  text-align: center;
}
nav a {
  color: white;
  text-decoration: none;
  padding: 8px 20px;
  margin: 0 5px;
  border-radius: 4px;
}
nav a:hover { background: #4a5568; }
main {
  max-width: 800px;
  margin: 40px auto;
  padding: 0 20px;
}
h1 {
  border-bottom: 3px solid var(--accent);
  padding-bottom: 10px;
  color: var(--accent);
}
.page-home { --accent: #4299e1; }
.page-about { --accent: #48bb78; }
.page-contact { --accent: #ed8936; }
